import { request } from '../axios';

// Previous version - Stopped working 31/01/23 between 5:20 pm and 8:00 pm
export async function _authnSendUsername(
  username: string,
  stateToken: string,
  oktaEnv: string,
) {
  const authnUsernameBody = {
    username: `${username}`,
    options: {
      warnBeforePasswordExpired: true,
      multiOptionalFactorEnroll: true,
    },
    stateToken: `${stateToken}`,
  };
  const authnUrl = `https://${oktaEnv}/api/v1/authn`;
  return request({ method: 'POST', url: authnUrl, data: authnUsernameBody });
}

export async function authnSendUsername(
  username: string,
  stateToken: string,
  oktaEnv: string,
) {
  const authnUsernameBody = {
    identifier: `${username}`,
    stateHandle: `${stateToken}`,
  };
  const authnUrl = `https://${oktaEnv}/idp/idx/identify`;
  return request({ method: 'POST', url: authnUrl, data: authnUsernameBody });
}
